import React from "react";
import { Card } from "flowbite-react";
import { Link } from "react-router-dom";

const MovieCard = () => {
  return (
    <div>
      <Link to={"/movies/details/12 "}>
        <div className=" {movies} ">
          <div className=" ms-4 me-4 flex flex-row md:col-span-4 lg:col-span-3 gap-4  justify-center ">
            <Card
              className="max-w-md"
              imgAlt="Meaningful alt text for an image that is not purely decorative"
              imgSrc="https://msp.c.yimg.jp/images/v2/FUTi93tXq405grZVGgDqGyXtFeY7do_C95WjwnQfNHZWchNkW6r_u1Znuql6-HifkKMFP0Dz8dY4-Fhrl3--BRuZh2Mezn5VCmwNH7F1qanPT6WPSHctAGhAvxhMRezg7HQCHBHnKBcqfqxrBzHp29xhPrqbOFe6oFNoFeFyiO6DY-_0IZgJrIWy3x9FIJ5TBa6gNuNs_GmOQrEVcl9wBJzU-mt4UhJnxCOPaJAzUc2JnHzukWlMbg6dxOSJsgh7C3MWCp5fQDmkKbGacLRzHEVKV7gASStXQE25nZcgxhaIa-OTgcc8scf8PDbl8eX4-Z11h8BQjR8Q4QBfClXMywyg-fK2FAQecbfSbgzM0YxqccJzceNd_TYm_NyxKB_0hAymUjJ__TGeEBghJlGvbw==/depositphotos_150614902-stock-photo-unusual-cinema-concept-3d-illustration.jpg?errorImage=false"
            >
              <h5 className="text-2xl font-bold tracking-tight text-gray-900 dark:text-white">
                Noteworthy technology acquisitions 2021
              </h5>
              <p className="">
                Streamlining your design process today. In today’s fast-paced
                digital landscape, fostering seamless collaboration among
                Developers and IT Operations.
              </p>
            </Card>
          </div>
        </div>
      </Link>
    </div>
  );
};

export default MovieCard;
